// src/hooks/useTuner.ts

import { useState, useEffect, useRef } from 'react';

// ❌ УДАЛЯЕМ — не используется
// const NOTE_STRINGS = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];

// 🔥 КАЛИБРОВКА: расширенный диапазон (E0-G7)
const NOTE_FREQUENCIES: Record<string, number> = {
  'C0': 16.35, 'C#0': 17.32, 'D0': 18.35, 'D#0': 19.45, 'E0': 20.60, 'F0': 21.83,
  'F#0': 23.12, 'G0': 24.50, 'G#0': 25.96, 'A0': 27.50, 'A#0': 29.14, 'B0': 30.87,
  'C1': 32.70, 'C#1': 34.65, 'D1': 36.71, 'D#1': 38.89, 'E1': 41.20, 'F1': 43.65,
  'F#1': 46.25, 'G1': 49.00, 'G#1': 51.91, 'A1': 55.00, 'A#1': 58.27, 'B1': 61.74,
  'C2': 65.41, 'C#2': 69.30, 'D2': 73.42, 'D#2': 77.78, 'E2': 82.41, 'F2': 87.31,
  'F#2': 92.50, 'G2': 98.00, 'G#2': 103.83, 'A2': 110.00, 'A#2': 116.54, 'B2': 123.47,
  'C3': 130.81, 'C#3': 138.59, 'D3': 146.83, 'D#3': 155.56, 'E3': 164.81, 'F3': 174.61,
  'F#3': 185.00, 'G3': 196.00, 'G#3': 207.65, 'A3': 220.00, 'A#3': 233.08, 'B3': 246.94,
  'C4': 261.63, 'C#4': 277.18, 'D4': 293.66, 'D#4': 311.13, 'E4': 329.63, 'F4': 349.23,
  'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'A#4': 466.16, 'B4': 493.88,
  'C5': 523.25, 'C#5': 554.37, 'D5': 587.33, 'D#5': 622.25, 'E5': 659.25, 'F5': 698.46,
  'F#5': 739.99, 'G5': 783.99, 'G#5': 830.61, 'A5': 880.00, 'A#5': 932.33, 'B5': 987.77,
  'C6': 1046.50, 'C#6': 1108.73, 'D6': 1174.66, 'D#6': 1244.51, 'E6': 1318.51, 'F6': 1396.91,
  'F#6': 1479.98, 'G6': 1567.98, 'G#6': 1661.22, 'A6': 1760.00, 'A#6': 1864.66, 'B6': 1975.53,
  'C7': 2093.00, 'C#7': 2217.46, 'D7': 2349.32, 'D#7': 2489.02, 'E7': 2637.02, 'F7': 2793.83,
  'F#7': 2959.96, 'G7': 3135.96
};

export const useTuner = () => {
  const [isActive, setIsActive] = useState(false);
  const [note, setNote] = useState<string>('-');
  const [cents, setCents] = useState<number>(0);
  const [frequency, setFrequency] = useState<number>(0);
  const [octave, setOctave] = useState<number>(4);
  const [signalStrength, setSignalStrength] = useState<number>(0);
  // ❌ УДАЛЯЕМ — не используется
  // const [noteHistory, setNoteHistory] = useState<string[]>([]);
  const [stability, setStability] = useState<number>(0);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const rafIdRef = useRef<number | null>(null);
  const historyRef = useRef<string[]>([]);

  const startTuner = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;
      
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = audioContext;
      
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 4096;
      analyser.smoothingTimeConstant = 0.8;
      analyserRef.current = analyser;

      const source = audioContext.createMediaStreamSource(stream);
      source.connect(analyser);

      setIsActive(true);
      tick();
    } catch (err) {
      console.error("Microphone access denied or error:", err);
      alert("Please allow microphone access to use the FretLab Tuner.");
    }
  };

  const stopTuner = () => {
    if (rafIdRef.current) cancelAnimationFrame(rafIdRef.current);
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    if (audioCtxRef.current) audioCtxRef.current.close();
    
    setIsActive(false);
    setNote('-');
    setCents(0);
    setFrequency(0);
    setSignalStrength(0);
    setStability(0);
  };

  const autoCorrelate = (buf: Float32Array, sampleRate: number) => {
    let SIZE = buf.length;
    let rms = 0;
    for (let i = 0; i < SIZE; i++) {
      const val = buf[i];
      rms += val * val;
    }
    rms = Math.sqrt(rms / SIZE);
    setSignalStrength(Math.min(1, rms * 20));

    if (rms < 0.005) return -1;

    let r1 = 0, r2 = SIZE - 1;
    const thres = 0.1;
    for (let i = 0; i < SIZE / 2; i++) {
      if (Math.abs(buf[i]) > thres) { r1 = i; break; }
    }
    for (let i = 1; i < SIZE / 2; i++) {
      if (Math.abs(buf[SIZE - i]) > thres) { r2 = SIZE - i; break; }
    }

    buf = buf.slice(r1, r2);
    SIZE = buf.length;
    if (SIZE < 100) return -1;

    const c = new Float32Array(SIZE);
    for (let i = 0; i < SIZE; i++) {
      let sum = 0;
      for (let j = 0; j < SIZE - i; j++) {
        sum += buf[j] * buf[j + i];
      }
      c[i] = sum / (SIZE - i);
    }

    let d = 0;
    while (d < SIZE - 1 && c[d] > c[d + 1]) d++;
    let maxVal = -1, maxPos = -1;
    for (let i = d; i < Math.min(SIZE, d + 1000); i++) {
      if (c[i] > maxVal) {
        maxVal = c[i];
        maxPos = i;
      }
    }
    if (maxPos < 0) return -1;

    const x1 = c[maxPos - 1] || 0;
    const x2 = c[maxPos];
    const x3 = c[maxPos + 1] || 0;
    const a = (x1 + x3 - 2 * x2) / 2;
    const b = (x3 - x1) / 2;
    let T0 = maxPos;
    if (a !== 0) T0 = maxPos - b / (2 * a);

    return sampleRate / T0;
  };

  const tick = () => {
    if (!analyserRef.current || !audioCtxRef.current) return;
    
    const buf = new Float32Array(analyserRef.current.fftSize);
    analyserRef.current.getFloatTimeDomainData(buf);
    const pitch = autoCorrelate(buf, audioCtxRef.current.sampleRate);
    
    if (pitch !== -1 && pitch > 30 && pitch < 5000) {
      const roundedPitch = Math.round(pitch);
      setFrequency(roundedPitch);

      let closestNote = 'A4';
      let closestFreq = 440;
      let minDiff = Infinity;
      let closestOctave = 4;

      for (const [noteName, freq] of Object.entries(NOTE_FREQUENCIES)) {
        const diff = Math.abs(pitch - freq);
        if (diff < minDiff) {
          minDiff = diff;
          closestNote = noteName;
          closestFreq = freq;
          closestOctave = parseInt(noteName.match(/\d+/)?.[0] || '4');
        }
      }

      const noteNameWithoutOctave = closestNote.replace(/\d+$/, '');
      const expectedFreq = closestFreq;
      let centsOff = Math.floor(1200 * Math.log2(pitch / expectedFreq));
      centsOff = Math.max(-50, Math.min(50, centsOff));

      historyRef.current.push(closestNote);
      if (historyRef.current.length > 10) historyRef.current.shift();

      const uniqueNotes = new Set(historyRef.current.slice(-5));
      const stabilityScore = 1 - (uniqueNotes.size - 1) / 5;
      setStability(Math.max(0, Math.min(1, stabilityScore)));

      if (stabilityScore > 0.5 || historyRef.current.length > 5) {
        setNote(noteNameWithoutOctave);
        setOctave(closestOctave);
        setCents(centsOff);
      } else {
        setNote('...');
      }
    } else {
      setNote('-');
      setCents(0);
      setStability(0);
      setSignalStrength(0);
    }

    rafIdRef.current = requestAnimationFrame(tick);
  };

  useEffect(() => {
    return () => stopTuner();
  }, []);

  return { isActive, startTuner, stopTuner, note, cents, frequency, octave, signalStrength, stability };
};