// src/components/ai/AISearchBar.tsx

import React, { useState, useRef, useEffect } from 'react';
import { processAIQuery, type TrackOption, type VideoPlatform } from '../../services/AIEngine';
import { useMusic } from '../../context/MusicContext';

interface AISearchBarProps {
  onAction?: (action: any) => void;
}

interface ChatMessage {
  id: string;
  role: 'user' | 'ai';
  text: string;
  timestamp: number;
  options?: TrackOption[];
  platformOptions?: { platform: VideoPlatform; label: string; icon: string }[];
  searchQuery?: string;
}

// 🔥 ПОДСКАЗКИ
const HINTS = [
  "Ask TouchGrass AI...",
  "🎸 Try: 'Find a blues backing track in Am'",
  "🎹 Try: 'Show me the Cmaj7 chord'",
  "🎼 Try: 'How to play over E7 alt?'",
  "⚡ Try: 'Generate a Dorian lick'"
];

// 🔥 КОМПОНЕНТ ВЫБОРА ПЛАТФОРМЫ
const PlatformSelector: React.FC<{ 
  platforms: { platform: VideoPlatform; label: string; icon: string }[];
  onSelect: (platform: VideoPlatform) => void;
}> = ({ platforms, onSelect }) => {
  return (
    <div style={{ display: 'flex', gap: '8px', marginTop: '12px', flexWrap: 'wrap' }}>
      {platforms.map(p => (
        <button
          key={p.platform}
          onClick={() => onSelect(p.platform)}
          style={{
            background: 'rgba(163, 116, 255, 0.15)',
            border: '1px solid var(--accent)',
            color: 'var(--accent)',
            padding: '8px 16px',
            borderRadius: '8px',
            cursor: 'pointer',
            fontSize: '12px',
            fontWeight: 800,
            transition: 'all 0.2s',
            display: 'flex',
            alignItems: 'center',
            gap: '6px',
          }}
          onMouseEnter={e => e.currentTarget.style.background = 'rgba(163, 116, 255, 0.3)'}
          onMouseLeave={e => e.currentTarget.style.background = 'rgba(163, 116, 255, 0.15)'}
        >
          {p.icon} {p.label}
        </button>
      ))}
    </div>
  );
};

// 🔥 КОМПОНЕНТ ОТОБРАЖЕНИЯ ОПЦИЙ
const OptionsRenderer: React.FC<{options: TrackOption[]}> = ({ options }) => {
  const { setKeyNote, setMode, setBpm, setCurrentTrack } = useMusic();
  
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginTop: '12px' }}>
      {options.map(opt => (
        <button 
          key={opt.id}
          onClick={() => {
            if (opt.key) setKeyNote(opt.key);
            if (opt.mode) setMode(opt.mode as any);
            if (opt.bpm) setBpm(opt.bpm);
            if (opt.action?.type === 'SET_CONTEXT' && opt.action.payload?.track) {
              setCurrentTrack(opt.action.payload.track);
            }
          }}
          style={{ 
            background: 'rgba(0, 255, 157, 0.1)', 
            border: '1px solid var(--accent)', 
            color: 'var(--accent)', 
            padding: '8px 12px', 
            borderRadius: '8px', 
            cursor: 'pointer', 
            textAlign: 'left', 
            fontSize: '12px', 
            fontWeight: 800, 
            transition: '0.2s' 
          }}
          onMouseEnter={e => e.currentTarget.style.background = 'rgba(0, 255, 157, 0.2)'}
          onMouseLeave={e => e.currentTarget.style.background = 'rgba(0, 255, 157, 0.1)'}
        >
          ▶ {opt.title}
        </button>
      ))}
    </div>
  );
};

const AISearchBar: React.FC<AISearchBarProps> = ({ onAction }) => {
  const { setCurrentTrack } = useMusic();
  const [query, setQuery] = useState('');
  const [modalQuery, setModalQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [hintIndex, setHintIndex] = useState(0);
  
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('fretlab_chat_history');
    return saved ? JSON.parse(saved) : [];
  });

  const [showFullChat, setShowFullChat] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('fretlab_chat_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    if (showFullChat) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [history, showFullChat]);

  useEffect(() => {
    const interval = setInterval(() => {
      setHintIndex((prev) => (prev + 1) % HINTS.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  const handlePlatformSelect = (platform: VideoPlatform, searchQuery: string) => {
    let searchUrl = '';
    const encodedQuery = encodeURIComponent(searchQuery);
    
    switch (platform) {
      case 'youtube':
        searchUrl = `https://www.youtube.com/results?search_query=${encodedQuery}`;
        break;
      case 'rutube':
        searchUrl = `https://rutube.ru/search/?query=${encodedQuery}`;
        break;
      case 'vk':
        searchUrl = `https://vk.com/video/search?q=${encodedQuery}`;
        break;
      default:
        return;
    }
    
    window.open(searchUrl, '_blank', 'noopener,noreferrer');
    
    const platformNames = { youtube: 'YouTube', rutube: 'RUTUBE', vk: 'VK Video' };
    const aiMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      role: 'ai',
      text: `🔍 Открываю поиск на ${platformNames[platform]} по запросу "${searchQuery}"...`,
      timestamp: Date.now(),
    };
    setHistory(prev => [...prev, aiMsg]);
  };

  const handleSubmit = async (text: string) => {
    if (!text.trim()) return;
    
    const userMsg: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text, 
      timestamp: Date.now() 
    };
    setHistory(prev => [...prev, userMsg]);
    setQuery('');
    setModalQuery('');
    setIsLoading(true);

    const response = await processAIQuery(text);
    
    const aiMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      role: 'ai',
      text: response.text,
      timestamp: Date.now(),
      options: response.options,
      platformOptions: response.platformOptions,
      searchQuery: response.searchQuery,
    };
    
    setHistory(prev => [...prev, aiMsg]);
    setIsLoading(false);

    if (response.action && onAction) {
      if (response.action.type === 'SET_CONTEXT' && response.action.payload?.track) {
        setCurrentTrack(response.action.payload.track);
      }
      onAction(response.action);
    }
  };

  const clearChat = () => {
    setHistory([]);
    localStorage.removeItem('fretlab_chat_history');
  };

  return (
    <div style={{ width: '100%', position: 'relative' }}>
      
      <div style={{ 
        display: 'flex', 
        alignItems: 'center', 
        gap: '8px', 
        background: 'var(--bg-secondary)', 
        border: '1px solid var(--border-color)', 
        borderRadius: '24px', 
        padding: '4px 16px', 
        transition: '0.2s', 
        width: '100%' 
      }}>
        <span style={{ fontSize: '16px' }}>🤖</span>
        <form onSubmit={e => { e.preventDefault(); handleSubmit(query); setShowFullChat(true); }} style={{ flex: 1 }}>
          <input 
            type="text" 
            value={query} 
            onChange={e => setQuery(e.target.value)} 
            placeholder={HINTS[hintIndex]} 
            style={{ 
              width: '100%', 
              background: 'transparent', 
              border: 'none', 
              color: 'var(--text-primary)', 
              outline: 'none', 
              fontSize: '13px', 
              padding: '8px 0' 
            }} 
          />
        </form>
        <button 
          onClick={() => setShowFullChat(true)} 
          style={{ 
            background: 'var(--bg-secondary)', 
            border: 'none', 
            color: 'var(--text-primary)', 
            borderRadius: '50%', 
            width: '28px', 
            height: '28px', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            cursor: 'pointer', 
            transition: '0.2s' 
          }} 
          title="Open Full Chat"
        >
          ⛶
        </button>
      </div>

      {showFullChat && (
        <div style={{ 
          position: 'fixed', 
          top: 0, 
          left: 0, 
          right: 0, 
          bottom: 0, 
          background: 'rgba(0,0,0,0.85)', 
          backdropFilter: 'blur(8px)',
          zIndex: 9999, 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px' 
        }}>
          <div style={{ 
            background: 'var(--bg-panel)', 
            width: '100%', 
            maxWidth: '800px', 
            height: '80vh', 
            borderRadius: '16px', 
            border: '1px solid var(--border-color)', 
            display: 'flex', 
            flexDirection: 'column', 
            overflow: 'hidden', 
            boxShadow: '0 24px 48px rgba(0,0,0,0.5)' 
          }}>
            
            <div style={{ 
              padding: '16px 24px', 
              background: 'var(--bg-primary)', 
              borderBottom: '1px solid var(--border-color)', 
              display: 'flex', 
              justifyContent: 'space-between', 
              alignItems: 'center' 
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <span style={{ fontSize: '24px' }}>🤖</span>
                <div>
                  <div style={{ color: 'var(--accent)', fontWeight: 900, fontSize: '16px', letterSpacing: '1px' }}>
                    TouchGrass AI
                  </div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '11px' }}>
                    Your Personal Music Assistant
                  </div>
                </div>
              </div>
              <div style={{ display: 'flex', gap: '12px' }}>
                <button 
                  onClick={clearChat} 
                  style={{ 
                    background: 'transparent', 
                    border: '1px solid var(--border-color)', 
                    color: 'var(--text-muted)', 
                    padding: '6px 12px', 
                    borderRadius: '8px', 
                    cursor: 'pointer', 
                    fontSize: '11px', 
                    fontWeight: 800,
                    transition: '0.2s'
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)'; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--border-color)'; e.currentTarget.style.color = 'var(--text-muted)'; }}
                >
                  🗑 CLEAR CHAT
                </button>
                <button 
                  onClick={() => setShowFullChat(false)} 
                  style={{ 
                    background: 'var(--bg-secondary)', 
                    border: 'none', 
                    color: 'var(--text-primary)', 
                    width: '32px', 
                    height: '32px', 
                    borderRadius: '50%', 
                    cursor: 'pointer', 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    fontWeight: 900,
                    transition: '0.2s'
                  }}
                  onMouseEnter={e => { e.currentTarget.style.background = 'var(--bg-hover)'; }}
                  onMouseLeave={e => { e.currentTarget.style.background = 'var(--bg-secondary)'; }}
                >
                  ✕
                </button>
              </div>
            </div>

            <div style={{ 
              flex: 1, 
              overflowY: 'auto', 
              padding: '24px', 
              display: 'flex', 
              flexDirection: 'column', 
              gap: '16px',
              background: 'var(--bg-root)'
            }}>
              {history.length === 0 && (
                <div style={{ 
                  margin: 'auto', 
                  textAlign: 'center', 
                  color: 'var(--text-muted)', 
                  maxWidth: '300px',
                  padding: '40px 0'
                }}>
                  <span style={{ fontSize: '48px', display: 'block', marginBottom: '16px', opacity: 0.2 }}>🎸</span>
                  Ask me to find a backing track, show a chord, or map an arpeggio on the fretboard!
                </div>
              )}
              
              {history.map(msg => (
                <div 
                  key={msg.id} 
                  style={{ 
                    display: 'flex', 
                    justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start',
                    animation: 'fadeIn 0.3s ease'
                  }}
                >
                  <div style={{ 
                    background: msg.role === 'user' ? 'var(--bg-secondary)' : 'var(--bg-primary)', 
                    color: 'var(--text-primary)', 
                    border: msg.role === 'user' ? '1px solid var(--accent)' : '1px solid var(--border-color)', 
                    padding: '12px 16px', 
                    borderRadius: msg.role === 'user' ? '16px 16px 4px 16px' : '16px 16px 16px 4px',
                    maxWidth: '85%', 
                    fontSize: '14px', 
                    lineHeight: '1.6',
                    boxShadow: msg.role === 'user' ? '0 2px 8px rgba(0,0,0,0.2)' : 'none'
                  }}>
                    <div style={{ 
                      fontSize: '10px', 
                      color: 'var(--text-muted)', 
                      marginBottom: '4px',
                      fontWeight: 600,
                      opacity: 0.6
                    }}>
                      {msg.role === 'user' ? '🧑 You' : '🤖 AI'}
                    </div>
                    {msg.text}
                    
                    {msg.options && <OptionsRenderer options={msg.options} />}
                    
                    {msg.platformOptions && msg.searchQuery && (
                      <PlatformSelector 
                        platforms={msg.platformOptions}
                        onSelect={(platform) => handlePlatformSelect(platform, msg.searchQuery!)}
                      />
                    )}
                  </div>
                </div>
              ))}
              
              {isLoading && (
                <div style={{ 
                  color: 'var(--text-muted)', 
                  fontSize: '13px',
                  padding: '8px 12px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span style={{ 
                    display: 'inline-block',
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: 'var(--accent)',
                    animation: 'pulse 1s infinite'
                  }} />
                  Thinking...
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            <div style={{ 
              padding: '20px 24px', 
              background: 'var(--bg-primary)', 
              borderTop: '1px solid var(--border-color)' 
            }}>
              <form onSubmit={e => { e.preventDefault(); handleSubmit(modalQuery); }} style={{ display: 'flex', gap: '12px' }}>
                <input 
                  type="text" 
                  value={modalQuery} 
                  onChange={e => setModalQuery(e.target.value)} 
                  placeholder={HINTS[hintIndex]} 
                  style={{ 
                    flex: 1, 
                    background: 'var(--bg-secondary)', 
                    color: 'var(--text-primary)', 
                    border: '1px solid var(--border-color)', 
                    padding: '12px 20px', 
                    borderRadius: '24px', 
                    outline: 'none',
                    fontSize: '14px',
                    transition: '0.2s'
                  }}
                  onFocus={e => { e.currentTarget.style.borderColor = 'var(--accent)'; }}
                  onBlur={e => { e.currentTarget.style.borderColor = 'var(--border-color)'; }}
                />
                <button 
                  type="submit" 
                  disabled={isLoading} 
                  style={{ 
                    background: isLoading ? 'var(--text-muted)' : 'var(--accent)', 
                    color: '#000', 
                    border: 'none', 
                    padding: '0 28px', 
                    borderRadius: '24px', 
                    fontWeight: 900, 
                    cursor: isLoading ? 'default' : 'pointer', 
                    transition: '0.2s',
                    fontSize: '13px',
                    letterSpacing: '0.5px'
                  }}
                  onMouseEnter={e => { if (!isLoading) e.currentTarget.style.transform = 'scale(1.02)'; }}
                  onMouseLeave={e => { if (!isLoading) e.currentTarget.style.transform = 'scale(1)'; }}
                >
                  SEND
                </button>
              </form>
            </div>

          </div>
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.3; transform: scale(0.8); }
        }
      `}</style>
    </div>
  );
};

export default AISearchBar;