// ============================================================
// 🔥 ГЕНЕРАТОР С МЕЛОДИЧНЫМИ ПАТТЕРНАМИ
// ============================================================

export const generateSmartLick = (
  scaleNotes: string[], 
  keyNote: string, 
  mode: string,
  bpm: number = 120
): Lick => {
  const pattern = GUITAR_PHRASES[Math.floor(Math.random() * GUITAR_PHRASES.length)];
  
  const startFret = Math.floor(Math.random() * 5) + 3;
  let currentString = Math.floor(Math.random() * 3) + 2;
  
  const notes: LickNote[] = [];
  let legatoGroupId = 0;
  
  for (let i = 0; i < pattern.intervals.length; i++) {
    // Выбираем ноту из гаммы с плавным движением
    let noteIndex = Math.floor(Math.random() * scaleNotes.length);
    if (i > 0 && notes.length > 0) {
      const direction = Math.random() > 0.5 ? 1 : -1;
      noteIndex = (noteIndex + direction * Math.floor(Math.random() * 2) + scaleNotes.length) % scaleNotes.length;
    }
    
    const selectedNote = scaleNotes[noteIndex];
    
    // Находим лад
    let fret = findFretForNote(selectedNote, currentString, 0, 15);
    
    // Корректируем позицию
    if (fret < startFret - 3 || fret > startFret + 5) {
      for (let attempt = 0; attempt < 3; attempt++) {
        const altString = Math.floor(Math.random() * 4) + 1;
        const altFret = findFretForNote(selectedNote, altString, 0, 12);
        if (altFret >= startFret - 2 && altFret <= startFret + 4) {
          currentString = altString;
          fret = altFret;
          break;
        }
      }
    }
    
    // Длительность из паттерна
    const duration = pattern.durations[i] as LickNote['duration'];
    
    // Техника из паттерна
    let technique = pattern.techniques[i] || 'none';
    
    // 🔥 ЛЕГАТО: только если есть группа и мы внутри неё
    let isLegatoEnd = false;
    let legatoGroup = undefined;
    
    if (pattern.legatoGroups) {
      for (const group of pattern.legatoGroups) {
        if (i >= group.start && i <= group.end) {
          legatoGroup = group;
          if (i === group.start) {
            technique = 'none';
          } else {
            technique = group.type;
          }
          if (i === group.end) {
            isLegatoEnd = true;
          }
          break;
        }
      }
    }
    
    // Акцент
    const isAccent = pattern.accentPositions.includes(i);
    
    // Динамика
    let velocity = isAccent ? 0.7 + Math.random() * 0.3 : 0.4 + Math.random() * 0.3;
    if (technique === 'hammer' || technique === 'pull') {
      velocity = velocity * 0.7;
    }
    
    // Связь с предыдущей нотой
    const tiedToNext = (i < pattern.intervals.length - 1 && 
                        Math.random() < 0.15 && 
                        notes.length > 0 && 
                        notes[notes.length - 1]?.string === currentString);
    
    notes.push({
      string: currentString,
      fret: Math.max(0, Math.min(24, fret)),
      duration,
      technique,
      tiedToNext,
      velocity,
      accent: isAccent,
      durationFactor: 0.9 + Math.random() * 0.2,
      legatoGroup: legatoGroup ? legatoGroupId : undefined,
      isLegatoEnd
    });
    
    if (legatoGroup && i === legatoGroup.end) {
      legatoGroupId++;
    }
  }
  
  const modeName = mode.replace(/_/g, ' ');
  const legatoLabel = pattern.legatoGroups && pattern.legatoGroups.length > 0 ? ' (Legato Accent)' : '';
  
  return {
    id: `lick-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`,
    name: `${pattern.name} ${keyNote} ${modeName}${legatoLabel}`,
    notes,
    tempo: bpm,
    swing: Math.random() * 0.2 + 0.05
  };
};